function lightlyRewriteQueuedTitle(value, rankCount) {
  const title = cleanQueuedValue(value);
  if (!title) return title;
  const replacements = [
    [/죽을 때까지 당부한/g, '죽을 때까지 당부했다는'],
    [/끝까지 당부한/g, '끝까지 당부했다는'],
    [/당부한/g, '당부했다는'],
    [/사람들이 하는/g, '사람들이 꼭 하는'],
    [/사람들이 챙긴/g, '사람들이 꼭 챙긴'],
    [/노화방지 식습관/g, '노화방지 식습관 체크'],
    [/건강비법$/g, '건강비법 정리'],
    [/운동법$/g, '운동법 루틴'],
    [/식습관$/g, '식습관 체크'],
    [/비법$/g, '비법 정리'],
    [/습관$/g, '습관 체크'],
  ];
  for (const [pattern, replacement] of replacements) {
    const changed = title.replace(pattern, replacement);
    if (changed !== title) return changed;
  }
  const count = Number(rankCount || 0);
  if (/[0-9０-９]/.test(title)) return title;
  if (count > 0 && title.length <= 24) {
    return title + ' ' + count + '가지';
  }
  return title + ' 체크';
}

