function limitPrompt(value, maxLength = 480) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (text.length <= maxLength) return text;
  return text.slice(0, maxLength).replace(/\s+\S*$/, '').trim();
}

function hashText(value) {
  let hash = 2166136261;
  const text = String(value || '');
  for (let index = 0; index < text.length; index += 1) {
    hash ^= text.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

function pick(items, salt) {
  return items[hashText([cfg.variation_seed, title, salt].join('|')) % items.length];
}

function findById(items, value) {
  const key = String(value || '').trim().toLowerCase();
  if (!key) return null;
  return items.find((item) => item.id.toLowerCase() === key || item.title.toLowerCase() === key) || null;
}

