function pickBgmProfile() {
  const override = findById(bgmProfiles, cfg.bgm_profile_override) || findById(bgmProfiles, pack.bgm_profile);
  if (override) return override;

  const historyPath = String(cfg.bgm_history_path || 'C:/dev/n8n-youtube-shorts-automation/.n8n/bgm-profile-history.json');
  let history = [];
  try {
    if (fs.existsSync(historyPath)) {
      history = JSON.parse(fs.readFileSync(historyPath, 'utf8'));
      if (!Array.isArray(history)) history = [];
    }
  } catch (error) {
    history = [];
  }

  const recentIds = new Set(history.slice(-5).map((entry) => entry && entry.id).filter(Boolean));
  const pool = bgmProfiles.filter((profile) => !recentIds.has(profile.id));
  const candidates = pool.length >= 6 ? pool : bgmProfiles;
  const picked = pick(candidates, 'bgm_profile|' + visualProfile.id + '|' + motifFamily + '|' + Array.from(recentIds).join(','));

  if (!cfg.disable_bgm_history_write) {
    try {
      fs.mkdirSync(historyPath.replace(/[\\/][^\\/]*$/, ''), { recursive: true });
      const nextHistory = [
        ...history.slice(-29),
        {
          id: picked.id,
          title: picked.title,
          hook_title: title,
          variation_seed: cfg.variation_seed || '',
          created_at: new Date().toISOString(),
        },
      ];
      fs.writeFileSync(historyPath, JSON.stringify(nextHistory, null, 2), 'utf8');
    } catch (error) {
      // BGM generation should continue even if local history cannot be written.
    }
  }

  return picked;
}

